package org.apache.commons.csv;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

public class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    public void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    public void testPrint_NullValue_NullStringNull() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        when(format.getNullString()).thenReturn(null);

        printer.print(null);

        // Verify that print(Object, String, int, int) is called with empty string
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, String.class, int.class, int.class);
        printMethod.setAccessible(true);
        // Since print(...) is private, we test through the public method and verify interactions
        verify(format).getNullString();
    }

    @Test
    public void testPrint_NullValue_NullStringNotNull() throws IOException {
        when(format.getNullString()).thenReturn("NULL");

        printer.print(null);

        verify(format).getNullString();
    }

    @Test
    public void testPrint_NonNullValue() throws IOException {
        String value = "testValue";

        printer.print(value);

        // Should call print with value.toString()
        verify(format, never()).getNullString();
    }

    @Test
    public void testPrint_InvokesPrivatePrint() throws Throwable {
        String value = "abc";
        String strValue = "abc";
        Method privatePrint = CSVPrinter.class.getDeclaredMethod("print", Object.class, String.class, int.class, int.class);
        privatePrint.setAccessible(true);

        // We invoke private print directly to ensure coverage
        privatePrint.invoke(printer, value, strValue, 0, strValue.length());
    }
}
